/* global Office */

import type { DataFlowEdge, DataFlowModel } from "../core/dataFlow";

type ParentMessage =
  | { action: "setDataFlow"; model: DataFlowModel | null }
  | { action: "selectionStatus"; message: string }
  | { action: "error"; message: string };

let model: DataFlowModel | null = null;
let selectedKey = "";
let lastStatus = "Loading...";
let activeRowIndex: number | null = null;
let activeColumnIndex: number | null = null;

function send(
  message:
    | { action: "ready" }
    | { action: "selectFlowLink"; fromSheet: string; toSheet: string }
    | { action: "exportDataFlow" }
    | { action: "close" }
): void {
  Office.context.ui.messageParent(JSON.stringify(message));
}

function parseMessage(raw: unknown): ParentMessage | null {
  if (typeof raw !== "string") return null;
  try {
    const parsed = JSON.parse(raw) as ParentMessage;
    if (parsed.action === "setDataFlow" || parsed.action === "selectionStatus" || parsed.action === "error") {
      return parsed;
    }
  } catch {
    return null;
  }
  return null;
}

function render(): void {
  const body = document.getElementById("matrixBody");
  const head = document.getElementById("matrixHead");
  if (!(body instanceof HTMLTableSectionElement) || !(head instanceof HTMLTableSectionElement)) return;
  body.textContent = "";
  head.textContent = "";
  if (!model) return;

  const edges = new Map(model.edges.map((edge) => [edgeKey(edge.fromSheet, edge.toSheet), edge]));
  const headerRow = document.createElement("tr");
  headerRow.appendChild(document.createElement("th"));
  model.sheets.forEach((sheet, columnIndex) => {
    const th = document.createElement("th");
    th.className = "column-sheet";
    th.dataset.columnIndex = String(columnIndex);
    th.title = renderSheetName(sheet.name, sheet.hidden);
    const span = document.createElement("span");
    span.textContent = renderSheetName(sheet.name, sheet.hidden);
    th.appendChild(span);
    headerRow.appendChild(th);
  });
  head.appendChild(headerRow);

  model.sheets.forEach((from, rowIndex) => {
    const tr = document.createElement("tr");
    const rowHead = document.createElement("th");
    rowHead.className = "row-sheet";
    rowHead.dataset.rowIndex = String(rowIndex);
    rowHead.textContent = renderSheetName(from.name, from.hidden);
    rowHead.title = rowHead.textContent;
    tr.appendChild(rowHead);
    model.sheets.forEach((to, columnIndex) => {
      const key = edgeKey(from.name, to.name);
      const edge = edges.get(key);
      const td = document.createElement("td");
      td.className = from.name === to.name ? "self" : "";
      td.dataset.rowIndex = String(rowIndex);
      td.dataset.columnIndex = String(columnIndex);
      td.addEventListener("mouseenter", () =>
        showCrosshair(rowIndex, columnIndex, `${renderSheetName(from.name, from.hidden)} -> ${renderSheetName(to.name, to.hidden)}`)
      );
      if (key === selectedKey) td.classList.add("selected");
      if (edge) {
        td.classList.add("link");
        td.dataset.edgeKey = key;
        td.textContent = String(edge.count);
        td.title = `${renderSheetName(from.name, from.hidden)} -> ${renderSheetName(to.name, to.hidden)}: ${edge.count}`;
        td.addEventListener("click", () => selectEdge(edge));
      }
      tr.appendChild(td);
    });
    body.appendChild(tr);
  });
}

function selectEdge(edge: DataFlowEdge): void {
  selectedKey = edgeKey(edge.fromSheet, edge.toSheet);
  const cell = document.querySelector(`[data-edge-key="${cssEscape(selectedKey)}"]`);
  if (cell instanceof HTMLElement) {
    activeRowIndex = Number(cell.dataset.rowIndex);
    activeColumnIndex = Number(cell.dataset.columnIndex);
  }
  applyActiveCrosshair();
  send({ action: "selectFlowLink", fromSheet: edge.fromSheet, toSheet: edge.toSheet });
  setStatus(`Selecting ${edge.count} formula cells: ${edge.fromSheet} -> ${edge.toSheet}`);
}

function applyModel(next: DataFlowModel | null): void {
  model = next;
  selectedKey = "";
  activeRowIndex = null;
  activeColumnIndex = null;
  const title = document.getElementById("title");
  if (title) title.textContent = "Data Flow";
  render();
  setStatus(model ? `${model.sheets.length} sheets, ${model.edges.length} links` : "No data flow links");
}

function setStatus(message: string, persist = true): void {
  if (persist) lastStatus = message;
  const status = document.getElementById("status");
  if (status) status.textContent = message;
}

function showCrosshair(rowIndex: number, columnIndex: number, label: string): void {
  document.querySelectorAll(".hover-row,.hover-col").forEach((element) => {
    element.classList.remove("hover-row", "hover-col");
  });
  document.querySelectorAll(`[data-row-index="${rowIndex}"]`).forEach((element) => element.classList.add("hover-row"));
  document.querySelectorAll(`[data-column-index="${columnIndex}"]`).forEach((element) => element.classList.add("hover-col"));
  setStatus(label, false);
}

function clearCrosshair(): void {
  document.querySelectorAll(".hover-row,.hover-col").forEach((element) => {
    element.classList.remove("hover-row", "hover-col");
  });
  applyActiveCrosshair();
  setStatus(lastStatus, false);
}

function applyActiveCrosshair(): void {
  document.querySelectorAll(".active-row,.active-col,.selected").forEach((element) => {
    element.classList.remove("active-row", "active-col", "selected");
  });
  if (activeRowIndex === null || activeColumnIndex === null) return;
  document.querySelectorAll(`[data-row-index="${activeRowIndex}"]`).forEach((element) => {
    element.classList.add("active-row");
  });
  document.querySelectorAll(`[data-column-index="${activeColumnIndex}"]`).forEach((element) => {
    element.classList.add("active-col");
  });
  document.querySelector(`[data-edge-key="${cssEscape(selectedKey)}"]`)?.classList.add("selected");
}

function edgeKey(fromSheet: string, toSheet: string): string {
  return `${fromSheet}\u0000${toSheet}`;
}

function renderSheetName(name: string, hidden: boolean): string {
  return hidden ? `${name} (hidden)` : name;
}

function cssEscape(value: string): string {
  return value.replace(/["\\]/g, "\\$&");
}

Office.onReady(() => {
  document.getElementById("closeBtn")?.addEventListener("click", () => send({ action: "close" }));
  document.getElementById("matrix")?.addEventListener("mouseleave", clearCrosshair);
  document.getElementById("exportLink")?.addEventListener("click", (event) => {
    event.preventDefault();
    send({ action: "exportDataFlow" });
  });
  Office.context.ui.addHandlerAsync(
    Office.EventType.DialogParentMessageReceived,
    (arg) => {
      const message = parseMessage("message" in arg ? arg.message : null);
      if (!message) return;
      if (message.action === "setDataFlow") applyModel(message.model);
      if (message.action === "selectionStatus") setStatus(message.message);
      if (message.action === "error") setStatus(message.message);
    },
    () => send({ action: "ready" })
  );
});
